    def _parse_websocket_key(self, key):
        magic = '258EAFA5-E914-47DA-95CA-C5AB0DC85B11'
        accept_key = key + magic
        sha1 = hashlib.sha1(accept_key.encode()).digest()
        return binascii.b2a_base64(sha1).strip()
        
    def _handle_handshake(self, client_socket, request):
        headers = {}
