    def _decode_websocket_frame(self, data):
        if len(data) < 2:
            return None
            
        byte1 = data[0]
        byte2 = data[1]
        
        fin = (byte1 & 0x80) != 0
        opcode = byte1 & 0x0F
        masked = (byte2 & 0x80) != 0
        payload_length = byte2 & 0x7F
        
