led = Pin(2, Pin.OUT)
device_state = {'led': False}

def handle_turn_on(data):
    led.on()
    device_state['led'] = True
    return {'led': 'on'}

def handle_turn_off(data):
    led.off()
    device_state['led'] = False
    return {'led': 'off'}

def handle_toggle(data):
    device_state['led'] = not device_state['led']
    if device_state['led']:
        led.on()
    else:
        led.off()
    return {'led': 'on' if device_state['led'] else 'off'}

def handle_status(data):
    return device_state

